// Standardize module input
const standardizedItems = items.map(item => ({
  json: {
    input_data: item.json,
    metadata: {
      workflow_id: $workflowId,
      execution_id: $executionId,
      timestamp: new Date().toISOString(),
      source_module: 'manual_trigger'
    },
    error_handling: {
      continue_on_error: true
    }
  }
}));

return standardizedItems;

// Module Processor Template
const results = [];
const errors = [];

for (const item of items) {
  try {
    const input = item.json.input_data;

    // YOUR MODULE LOGIC GOES HERE
    const processedData = {
      received_data: input,
      processed_at: new Date().toISOString()
    };

    results.push({
      json: {
        success: true,
        data: processedData,
        metadata: {
          module_name: 'Template_Module',
          items_processed: 1
        }
      }
    });

  } catch (error) {
    errors.push({
      json: {
        error: true,
        error_message: error.message,
        error_code: 'PROCESSING_ERROR'
      }
    });
  }
}

// Return results + errors
return [...results, ...errors];
